import pytest
from appium import webdriver
from appium.options.android import UiAutomator2Options

class TestBluetoothConnection:
    @pytest.fixture(scope="function")
    def driver(self):
        options = UiAutomator2Options()
        options.platform_name = "Android"
        options.device_name = "Pixel 8 Pro"
        options.app_package = "com.android.settings"
        options.app_activity = ".Settings"
        options.no_reset = True

        driver = webdriver.Remote("http://localhost:4723", options=options)
        yield driver
        driver.quit()

    def test_enable_bluetooth(self, driver):
        # Step 1: Open Bluetooth settings
        driver.find_element_by_android_uiautomator('new UiSelector().text("Bluetooth")').click()
        # Step 2: Enable Bluetooth if not enabled
        toggle = driver.find_element_by_id("android:id/switch_widget")
        if toggle.text == "OFF":
            toggle.click()
        assert toggle.text == "ON"

